class Game {
    constructor(canvas, ctx) {
        this.canvas = canvas;
        this.ctx = ctx;
        this.width = canvas.width;
        this.height = canvas.height;

        this.input = new Input();
        this.player = new Player(this.width / 2, this.height - 100);

        this.bullets = [];
        this.enemies = [];
        this.particles = [];
        this.powerUps = [];
        this.stars = [];

        this.score = 0;
        this.wave = 1;
        this.waveTimer = 0;
        this.enemySpawnTimer = 0;
        this.gameOver = false;
        this.paused = false;

        this.setupStars();
    }

    setupStars() {
        // Create background stars
        for (let i = 0; i < 100; i++) {
            this.stars.push({
                x: Math.random() * this.width,
                y: Math.random() * this.height,
                size: Math.random() * 2,
                speed: Math.random() * 0.5 + 0.1
            });
        }
    }

    start() {
        this.lastTime = performance.now();
        requestAnimationFrame((t) => this.loop(t));
    }

    loop(timestamp) {
        const deltaTime = (timestamp - this.lastTime) / 1000;
        this.lastTime = timestamp;

        if (!this.paused && !this.gameOver) {
            this.update(deltaTime);
        }
        this.render();

        requestAnimationFrame((t) => this.loop(t));
    }

    update(dt) {
        // Cap delta time
        dt = Math.min(dt, 0.1);

        // Update stars
        this.stars.forEach(star => {
            star.y += star.speed * 60 * dt;
            if (star.y > this.height) {
                star.y = 0;
                star.x = Math.random() * this.width;
            }
        });

        // Update player
        this.player.update(dt, this.input, this);

        // Update bullets
        this.bullets = this.bullets.filter(b => b.active);
        this.bullets.forEach(b => b.update(dt));

        // Update enemies
        this.enemies = this.enemies.filter(e => e.active && e.y < this.height + 50);
        this.enemies.forEach(e => e.update(dt, this));

        // Update particles
        this.particles = this.particles.filter(p => p.life > 0);
        this.particles.forEach(p => p.update(dt));

        // Update power-ups
        this.powerUps = this.powerUps.filter(p => p.active);
        this.powerUps.forEach(p => p.update(dt));

        // Spawn enemies
        this.spawnEnemies(dt);

        // Check collisions
        this.checkCollisions();

        // Update UI
        this.updateUI();

        // Check game over
        if (this.player.health <= 0) {
            this.endGame();
        }
    }

    spawnEnemies(dt) {
        this.enemySpawnTimer += dt;
        const spawnRate = Math.max(0.3, 1.0 - this.wave * 0.1);

        if (this.enemySpawnTimer > spawnRate) {
            this.enemySpawnTimer = 0;

            const types = ['basic', 'fast', 'tank'];
            const type = types[Math.floor(Math.random() * types.length)];
            const x = Math.random() * (this.width - 40) + 20;

            this.enemies.push(new Enemy(x, -30, type));
        }

        // Increase wave every 10 seconds
        this.waveTimer += dt;
        if (this.waveTimer > 10) {
            this.waveTimer = 0;
            this.wave++;
            this.showWaveMessage();
        }
    }

    showWaveMessage() {
        // Could show wave notification
        console.log('Wave ' + this.wave);
    }

    checkCollisions() {
        // Bullets vs Enemies
        this.bullets.forEach(bullet => {
            if (!bullet.active) return;

            this.enemies.forEach(enemy => {
                if (!enemy.active) return;

                if (this.checkOverlap(bullet, enemy)) {
                    bullet.active = false;
                    enemy.takeDamage(bullet.damage);

                    if (enemy.health <= 0) {
                        this.score += enemy.scoreValue;
                        this.createExplosion(enemy.x, enemy.y, enemy.color);

                        // Chance to drop power-up
                        if (Math.random() < 0.1) {
                            this.powerUps.push(new PowerUp(enemy.x, enemy.y));
                        }
                    }
                }
            });
        });

        // Player vs Enemies
        this.enemies.forEach(enemy => {
            if (!enemy.active) return;

            if (this.checkOverlap(this.player, enemy)) {
                this.player.takeDamage(20);
                enemy.active = false;
                this.createExplosion(enemy.x, enemy.y, '#f44');
            }
        });

        // Player vs Power-ups
        this.powerUps.forEach(powerUp => {
            if (!powerUp.active) return;

            if (this.checkOverlap(this.player, powerUp)) {
                powerUp.apply(this.player);
                powerUp.active = false;
            }
        });
    }

    checkOverlap(a, b) {
        return a.x < b.x + b.width &&
               a.x + a.width > b.x &&
               a.y < b.y + b.height &&
               a.y + a.height > b.y;
    }

    createExplosion(x, y, color) {
        for (let i = 0; i < 15; i++) {
            const angle = (Math.PI * 2 * i) / 15;
            const speed = Math.random() * 100 + 50;
            this.particles.push(new Particle(
                x, y,
                Math.cos(angle) * speed,
                Math.sin(angle) * speed,
                color,
                0.5
            ));
        }
    }

    updateUI() {
        document.getElementById('score').textContent = this.score;
        document.getElementById('health').textContent = Math.max(0, this.player.health);
        document.getElementById('wave').textContent = this.wave;
    }

    endGame() {
        this.gameOver = true;
        document.getElementById('final-score').textContent = this.score;
        document.getElementById('game-over').style.display = 'block';
    }

    restart() {
        this.player = new Player(this.width / 2, this.height - 100);
        this.bullets = [];
        this.enemies = [];
        this.particles = [];
        this.powerUps = [];
        this.score = 0;
        this.wave = 1;
        this.waveTimer = 0;
        this.gameOver = false;
        document.getElementById('game-over').style.display = 'none';
    }

    render() {
        // Clear with fade effect for motion blur
        this.ctx.fillStyle = 'rgba(10, 10, 46, 0.3)';
        this.ctx.fillRect(0, 0, this.width, this.height);

        // Draw stars
        this.ctx.fillStyle = '#fff';
        this.stars.forEach(star => {
            this.ctx.globalAlpha = Math.random() * 0.5 + 0.3;
            this.ctx.fillRect(star.x, star.y, star.size, star.size);
        });
        this.ctx.globalAlpha = 1;

        // Draw power-ups
        this.powerUps.forEach(p => p.render(this.ctx));

        // Draw bullets
        this.bullets.forEach(b => b.render(this.ctx));

        // Draw enemies
        this.enemies.forEach(e => e.render(this.ctx));

        // Draw player
        this.player.render(this.ctx);

        // Draw particles
        this.particles.forEach(p => p.render(this.ctx));
    }
}

