class Player {
    constructor(x, y) {
        this.x = x;
        this.y = y;
        this.width = 40;
        this.height = 40;
        this.speed = 300;
        this.health = 100;
        this.maxHealth = 100;

        this.shootTimer = 0;
        this.shootCooldown = 0.15;
        this.tripleShot = false;
        this.tripleShotTimer = 0;

        this.invulnerable = false;
        this.invulnerableTimer = 0;
    }

    update(dt, input, game) {
        // Movement
        if (input.isPressed('ArrowLeft') || input.isPressed('KeyA')) {
            this.x -= this.speed * dt;
        }
        if (input.isPressed('ArrowRight') || input.isPressed('KeyD')) {
            this.x += this.speed * dt;
        }
        if (input.isPressed('ArrowUp') || input.isPressed('KeyW')) {
            this.y -= this.speed * dt;
        }
        if (input.isPressed('ArrowDown') || input.isPressed('KeyS')) {
            this.y += this.speed * dt;
        }

        // Clamp to screen
        this.x = Math.max(0, Math.min(game.width - this.width, this.x));
        this.y = Math.max(0, Math.min(game.height - this.height, this.y));

        // Shooting
        this.shootTimer += dt;
        if (input.isPressed('Space') && this.shootTimer > this.shootCooldown) {
            this.shoot(game);
            this.shootTimer = 0;
        }

        // Power-up timers
        if (this.tripleShot) {
            this.tripleShotTimer -= dt;
            if (this.tripleShotTimer <= 0) {
                this.tripleShot = false;
            }
        }

        if (this.invulnerable) {
            this.invulnerableTimer -= dt;
            if (this.invulnerableTimer <= 0) {
                this.invulnerable = false;
            }
        }
    }

    shoot(game) {
        const bulletX = this.x + this.width / 2 - 3;
        const bulletY = this.y;

        if (this.tripleShot) {
            // Triple shot
            game.bullets.push(new Bullet(bulletX, bulletY, 0, -600, '#0ff'));
            game.bullets.push(new Bullet(bulletX, bulletY, -150, -550, '#0ff'));
            game.bullets.push(new Bullet(bulletX, bulletY, 150, -550, '#0ff'));
        } else {
            // Single shot
            game.bullets.push(new Bullet(bulletX, bulletY, 0, -600, '#0ff'));
        }
    }

    takeDamage(amount) {
        if (this.invulnerable) return;

        this.health -= amount;
        this.invulnerable = true;
        this.invulnerableTimer = 1.0;
    }

    heal(amount) {
        this.health = Math.min(this.maxHealth, this.health + amount);
    }

    render(ctx) {
        ctx.save();

        // Flicker when invulnerable
        if (this.invulnerable && Math.floor(Date.now() / 100) % 2 === 0) {
            ctx.globalAlpha = 0.5;
        }

        // Draw ship body
        ctx.fillStyle = '#0ff';
        ctx.beginPath();
        ctx.moveTo(this.x + this.width / 2, this.y);
        ctx.lineTo(this.x + this.width, this.y + this.height);
        ctx.lineTo(this.x + this.width / 2, this.y + this.height - 10);
        ctx.lineTo(this.x, this.y + this.height);
        ctx.closePath();
        ctx.fill();

        // Draw cockpit
        ctx.fillStyle = '#fff';
        ctx.beginPath();
        ctx.arc(this.x + this.width / 2, this.y + 20, 5, 0, Math.PI * 2);
        ctx.fill();

        // Draw engine glow
        ctx.fillStyle = '#0af';
        ctx.shadowBlur = 20;
        ctx.shadowColor = '#0af';
        ctx.fillRect(this.x + 15, this.y + this.height - 5, 10, 10);
        ctx.shadowBlur = 0;

        // Draw engine particles
        if (Math.random() < 0.5) {
            ctx.fillStyle = '#0ff';
            ctx.fillRect(
                this.x + 10 + Math.random() * 20,
                this.y + this.height,
                2, 5
            );
        }

        ctx.restore();
    }
}

