class Enemy {
    constructor(x, y, type) {
        this.x = x;
        this.y = y;
        this.type = type;
        this.active = true;

        // Stats based on type
        switch(type) {
            case 'fast':
                this.width = 25;
                this.height = 25;
                this.speed = 200;
                this.health = 30;
                this.scoreValue = 30;
                this.color = '#f84';
                break;
            case 'tank':
                this.width = 50;
                this.height = 50;
                this.speed = 50;
                this.health = 100;
                this.scoreValue = 50;
                this.color = '#848';
                break;
            default: // basic
                this.width = 35;
                this.height = 35;
                this.speed = 100;
                this.health = 50;
                this.scoreValue = 10;
                this.color = '#f44';
        }

        this.velocityX = 0;
        this.wobble = Math.random() * Math.PI * 2;
    }

    update(dt, game) {
        this.y += this.speed * dt;

        // Wobble movement for fast enemies
        if (this.type === 'fast') {
            this.wobble += dt * 3;
            this.x += Math.sin(this.wobble) * 50 * dt;
        }

        // Basic enemy shoots occasionally
        if (this.type === 'basic' && Math.random() < 0.001) {
            // Could shoot at player
        }
    }

    takeDamage(amount) {
        this.health -= amount;
        if (this.health <= 0) {
            this.active = false;
        }
    }

    render(ctx) {
        ctx.fillStyle = this.color;

        switch(this.type) {
            case 'fast':
                // Diamond shape
                ctx.beginPath();
                ctx.moveTo(this.x + this.width / 2, this.y);
                ctx.lineTo(this.x + this.width, this.y + this.height / 2);
                ctx.lineTo(this.x + this.width / 2, this.y + this.height);
                ctx.lineTo(this.x, this.y + this.height / 2);
                ctx.closePath();
                ctx.fill();
                break;

            case 'tank':
                // Hexagon
                ctx.beginPath();
                for (let i = 0; i < 6; i++) {
                    const angle = (Math.PI / 3) * i;
                    const px = this.x + this.width / 2 + Math.cos(angle) * this.width / 2;
                    const py = this.y + this.height / 2 + Math.sin(angle) * this.height / 2;
                    if (i === 0) ctx.moveTo(px, py);
                    else ctx.lineTo(px, py);
                }
                ctx.closePath();
                ctx.fill();
                break;

            default:
                // Square with detail
                ctx.fillRect(this.x, this.y, this.width, this.height);
                ctx.fillStyle = '#000';
                ctx.fillRect(this.x + 8, this.y + 8, this.width - 16, this.height - 16);
        }

        // Health bar for tank
        if (this.type === 'tank') {
            const healthPercent = this.health / 100;
            ctx.fillStyle = '#000';
            ctx.fillRect(this.x, this.y - 10, this.width, 5);
            ctx.fillStyle = healthPercent > 0.5 ? '#0f0' : '#f00';
            ctx.fillRect(this.x, this.y - 10, this.width * healthPercent, 5);
        }
    }
}

