class PowerUp {
    constructor(x, y) {
        this.x = x;
        this.y = y;
        this.width = 25;
        this.height = 25;
        this.active = true;
        this.speed = 100;
        this.rotation = 0;

        // Random type
        const types = ['health', 'triple', 'rapid'];
        this.type = types[Math.floor(Math.random() * types.length)];

        switch(this.type) {
            case 'health':
                this.color = '#0f0';
                break;
            case 'triple':
                this.color = '#ff0';
                break;
            case 'rapid':
                this.color = '#f0f';
                break;
        }
    }

    update(dt) {
        this.y += this.speed * dt;
        this.rotation += dt * 2;

        if (this.y > 850) {
            this.active = false;
        }
    }

    apply(player) {
        switch(this.type) {
            case 'health':
                player.heal(30);
                break;
            case 'triple':
                player.tripleShot = true;
                player.tripleShotTimer = 10;
                break;
            case 'rapid':
                player.shootCooldown = 0.05;
                setTimeout(() => {
                    player.shootCooldown = 0.15;
                }, 5000);
                break;
        }
    }

    render(ctx) {
        ctx.save();
        ctx.translate(this.x + this.width / 2, this.y + this.height / 2);
        ctx.rotate(this.rotation);

        ctx.fillStyle = this.color;
        ctx.shadowBlur = 15;
        ctx.shadowColor = this.color;

        // Draw power-up shape
        ctx.beginPath();
        ctx.arc(0, 0, this.width / 2, 0, Math.PI * 2);
        ctx.fill();

        // Draw symbol
        ctx.fillStyle = '#000';
        ctx.font = 'bold 14px Arial';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';

        const symbol = this.type === 'health' ? '+' :
                      this.type === 'triple' ? '3' : 'R';
        ctx.fillText(symbol, 0, 0);

        ctx.restore();
    }
}

